// Prepare vector data for Pinecone upsert
const inputData = $input.first().json;

// Validate that we have embedding data
if (!inputData.embedding || !inputData.embedding.vector) {
  throw new Error('No embedding vector provided');
}

// Prepare metadata (Pinecone has limits on metadata size)
const metadata = {
  // Core identifiers
  call_id: inputData.call_id,

  // Participant info
  caller_name: inputData.metadata?.caller_name || 'Unknown',
  agent_name: inputData.metadata?.agent_name || 'Unknown',
  caller_number_hash: inputData.metadata?.caller_number ? 
    Buffer.from(inputData.metadata.caller_number).toString('base64').substring(0, 20) : null,

  // Timing
  call_date: inputData.metadata?.started_at ? 
    new Date(inputData.metadata.started_at).toISOString().split('T')[0] : null,
  duration_minutes: Math.ceil((inputData.metadata?.duration_seconds || 0) / 60),

  // Analysis results
  summary: (inputData.analysis?.summary || '').substring(0, 500), // Limit size
  customer_intent: inputData.analysis?.customer_intent || 'Unknown',
  resolution_status: inputData.analysis?.resolution_status || 'unknown',
  sentiment: inputData.analysis?.sentiment?.label || 'neutral',
  sentiment_score: inputData.analysis?.sentiment?.confidence || 0,

  // Topics (as comma-separated for filtering)
  topics: (inputData.analysis?.topics || []).slice(0, 10).join(','),

  // Entities
  entities: (inputData.analysis?.entities || []).slice(0, 10).join(','),

  // Direction
  call_direction: inputData.metadata?.direction || 'inbound',

  // Integration references
  hubspot_contact_id: inputData.integrations?.hubspot_contact_id || null,

  // Processing info
  indexed_at: new Date().toISOString()
};

// Pinecone upsert format
const pineconePayload = {
  vectors: [
    {
      id: `call_${inputData.call_id}`,
      values: inputData.embedding.vector,
      metadata: metadata
    }
  ],
  namespace: 'call_transcripts'
};

return { json: pineconePayload };

// Return success response
const inputData = $('Vector Sync Trigger').first().json;
const pineconeResponse = $('Upsert to Pinecone').first().json;

return {
  json: {
    status: 'success',
    call_id: inputData.call_id,
    vector_id: `call_${inputData.call_id}`,
    namespace: 'call_transcripts',
    upserted_count: pineconeResponse.upsertedCount || 1,
    indexed_at: new Date().toISOString()
  }
};

// Handle Pinecone error
const error = $input.first().json;
const inputData = $('Vector Sync Trigger').first().json;

return {
  json: {
    status: 'error',
    call_id: inputData.call_id,
    error_message: error.message || 'Pinecone upsert failed',
    retry_eligible: true,
    failed_at: new Date().toISOString()
  }
};
